:root {
  --bg-card: #ffffff;
  --bg-header: #1a1f2e;
  --bg-footer: #f8f9fb;
  --bg-item-hover: #f4f6ff;
  --border-color: #e4e8f0;
  --text-primary: #1a1f2e;
  --text-secondary: #6b7491;
  --text-header: #ffffff;
  --text-meta: #9199b5;
  --status-ready: #22c55e;
  --status-review: #f59e0b;
  --status-changes: #ef4444;
  --status-draft: #9199b5;
  --badge-approved-bg: #dcfce7;
  --badge-approved-text: #16a34a;
  --badge-review-bg: #fef3c7;
  --badge-review-text: #d97706;
  --badge-changes-bg: #fee2e2;
  --badge-changes-text: #dc2626;
  --badge-draft-bg: #f1f2f6;
  --badge-draft-text: #6b7491;
  --stat-value-color: #1a1f2e;
  --divider-color: #d1d5e8;
}

.dashboard {
  width: 320px;
  background: var(--bg-card);
  border-radius: 14px;
  border: 1px solid var(--border-color);
  overflow: hidden;
  margin: 20px auto;
}

.dash-header {
  background: var(--bg-header);
  padding: 16px 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.dash-title {
  font-size: 15px;
  font-weight: 700;
  color: var(--text-header);
  letter-spacing: 0.3px;
}

.dash-count {
  font-size: 12px;
  font-weight: 500;
  color: var(--text-meta);
  background: rgba(255, 255, 255, 0.1);
  padding: 3px 10px;
  border-radius: 20px;
}

.pr-list {
  padding: 8px 0;
}

.pr-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 20px;
  border-bottom: 1px solid var(--border-color);
}

.pr-item:last-child {
  border-bottom: none;
}

.pr-status {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

.status-ready { background: var(--status-ready); }
.status-review { background: var(--status-review); }
.status-changes { background: var(--status-changes); }
.status-draft { background: var(--status-draft); }

.pr-info {
  display: flex;
  flex-direction: column;
  gap: 3px;
  flex: 1;
  min-width: 0;
}

.pr-name {
  font-size: 13px;
  font-weight: 500;
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.pr-meta {
  font-size: 11px;
  color: var(--text-meta);
}

.pr-badge {
  font-size: 10px;
  font-weight: 600;
  padding: 3px 8px;
  border-radius: 20px;
  white-space: nowrap;
  flex-shrink: 0;
  text-transform: uppercase;
  letter-spacing: 0.4px;
}

.badge-approved {
  background: var(--badge-approved-bg);
  color: var(--badge-approved-text);
}

.badge-review {
  background: var(--badge-review-bg);
  color: var(--badge-review-text);
}

.badge-changes {
  background: var(--badge-changes-bg);
  color: var(--badge-changes-text);
}

.badge-draft {
  background: var(--badge-draft-bg);
  color: var(--badge-draft-text);
}

.dash-footer {
  background: var(--bg-footer);
  border-top: 1px solid var(--border-color);
  padding: 14px 20px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 24px;
}

.stat {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}

.stat-value {
  font-size: 18px;
  font-weight: 700;
  color: var(--stat-value-color);
  line-height: 1;
}

.stat-label {
  font-size: 11px;
  color: var(--text-secondary);
  font-weight: 400;
}

.stat-divider {
  width: 1px;
  height: 28px;
  background: var(--divider-color);
}
